def valid_date(date):
    # Check if the date string is empty
    if not date:
        return False

    # Check the format: mm-dd-yyyy
    parts = date.split('-')
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    # Check if each part has the correct number of digits
    if len(month_str) != 2 or len(day_str) != 2 or len(year_str) != 4:
        return False

    # Check if all parts are numeric
    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    # Convert to integers
    month = int(month_str)
    day = int(day_str)
    year = int(year_str)

    # Check month range
    if month < 1 or month > 12:
        return False

    # Check day range based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        if day < 1 or day > 30:
            return False
    elif month == 2:
        if day < 1 or day > 29:
            return False

    return True
